const item = items[0];
const now = Date.now();
// multipart/form-data: textová pole jsou pod item.json.body
const body = item.json.body || item.json;
const eventId = String(body.event || '').trim() || 'UNKNOWN';

// Načti binární data fotky výrobku
let photoBase64 = '';
try {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'photo');
  photoBase64 = buffer.toString('base64');
} catch(e1) {
  try {
    const buffer = await helpers.getBinaryDataBuffer(item, 'photo');
    photoBase64 = buffer.toString('base64');
  } catch(e2) {
    photoBase64 = (item.binary?.photo?.data ?? '').replace(/[\r\n\s]/g, '');
  }
}

// Načti binární data fotky instrukcí (volitelné)
let instructionsBase64 = '';
try {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'instructions');
  instructionsBase64 = buffer.toString('base64');
} catch(e1) {
  try {
    const buffer = await helpers.getBinaryDataBuffer(item, 'instructions');
    instructionsBase64 = buffer.toString('base64');
  } catch(e2) {
    instructionsBase64 = (item.binary?.instructions?.data ?? '').replace(/[\r\n\s]/g, '');
  }
}

return [{
  json: {
    team:                  String(body.team || '').trim(),
    description:           String(body.description || '').trim(),
    eventId,
    // Commit přímo do main — žádné PR větve
    branchName:            'main',
    photoRepoPath:         `public/images/submissions/${eventId}/${now}.jpg`,
    photoPublicPath:       `/images/submissions/${eventId}/${now}.jpg`,
    instructionsRepoPath:  `public/images/submissions/${eventId}/${now}-instructions.jpg`,
    instructionsPublicPath:`/images/submissions/${eventId}/${now}-instructions.jpg`,
    activitiesPath:        `public/content/events/${eventId}/activities.json`,
    activityId:            String(now),
    photoBase64,
    instructionsBase64
  }
}];

const item = items[0];
let instructionsText = '';
// Mistral OCR vrací { pages: [{ markdown: '...' }] }
if (Array.isArray(item.json?.pages) && item.json.pages.length > 0) {
  instructionsText = item.json.pages.map(p => p.markdown || '').join('\n').trim();
}
// Fallback: chat completions formát
if (!instructionsText && item.json?.choices?.[0]?.message?.content) {
  instructionsText = item.json.choices[0].message.content.trim();
}
return [{ json: { instructionsText } }];

const item = items[0];
// Pokud korekce proběhla, použij opravený text
const corrected = item.json?.choices?.[0]?.message?.content?.trim() || '';
// Fallback na původní OCR text
const original  = $node['Extrahuj text OCR'].json.instructionsText || '';
return [{ json: { instructionsText: corrected || original } }];

const item = items[0];
const prep = $node['Připrav data'].json;
const ghFile = $node['Načti activities.json'].json;
const instructionsText = $node['Extrahuj korekci'].json.instructionsText || '';

// SHA existujícího souboru — nutné pro GitHub PUT update (bez SHA vrátí 422)
const activitiesSha = ghFile?.sha || null;

// Dekóduj stávající activities.json, nebo začni prázdný
let current = { eventId: prep.eventId, title: '', activities: [] };
if (ghFile && ghFile.content) {
  try {
    current = JSON.parse(Buffer.from(ghFile.content, 'base64').toString('utf-8'));
  } catch(e) {}
}

// Přidej novou aktivitu
current.activities = current.activities || [];
current.activities.push({
  id:                   prep.activityId,
  title:                prep.team,
  description:          prep.description,
  url:                  '',
  btnLabel:             'Zobrazit',
  photo:                prep.photoPublicPath,
  instructionsPhoto:    prep.instructionsBase64 ? prep.instructionsPublicPath : '',
  instructionsText
});

const newActivitiesBase64 = Buffer.from(JSON.stringify(current, null, 2)).toString('base64');

return [{
  json: {
    ...prep,
    newActivitiesBase64,
    activitiesSha
  }
}];

// Připraví URL a body pro nahrání fotky instrukcí
// Pokud instructions nebyly nahrány, vrátí prázdné stringy → Nahraj foto instrukcí selže tiše (continueOnFail)
const d = $('Sestav activities.json').item.json;

return [{
  json: {
    instrUrl:  'https://api.github.com/repos/chmelainv/AI-nadsenci-web/contents/' + d.instructionsRepoPath,
    instrBody: JSON.stringify({
      message: 'submission: instrukce ' + d.team,
      content: d.instructionsBase64,
      branch:  d.branchName
    })
  }
}];

// Připraví URL a body pro nahrání activities.json jako plain string
// (komplexní výrazy v HTTP Request URL/body polích v n8n mohou selhat s 'invalid syntax')
const d = $('Sestav activities.json').item.json;

const bodyObj = {
  message: 'submission: data ' + d.team,
  content: d.newActivitiesBase64,
  branch:  d.branchName
};
// SHA je povinné pokud soubor již existuje, jinak GitHub vrátí 422
if (d.activitiesSha) bodyObj.sha = d.activitiesSha;

return [{
  json: {
    uploadUrl:  'https://api.github.com/repos/chmelainv/AI-nadsenci-web/contents/' + d.activitiesPath,
    uploadBody: JSON.stringify(bodyObj),
    // metadata pro Vytvoř PR
    team:            d.team,
    description:     d.description,
    photoPublicPath: d.photoPublicPath,
    branchName:      d.branchName
  }
}];
